import{_ as e,o as t,c as r,a1 as o}from"./chunks/framework.qq2wtA-j.js";const h=JSON.parse('{"title":"其它脚本","description":"","frontmatter":{},"headers":[],"relativePath":"aegisub-automation/other-scripts.md","filePath":"aegisub-automation/other-scripts.md"}'),l={name:"aegisub-automation/other-scripts.md"};function i(s,a,d,n,c,g){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="其它脚本" tabindex="-1">其它脚本 <a class="header-anchor" href="#其它脚本" aria-label="Permalink to &quot;其它脚本&quot;">​</a></h1><p>本章包含不属于辅助脚本分类的其它资源，包括部分 Lua 脚本和字幕模板文件。</p><h2 id="行内容编辑" tabindex="-1">行内容编辑 <a class="header-anchor" href="#行内容编辑" aria-label="Permalink to &quot;行内容编辑&quot;">​</a></h2><p>本章节下的 Lua 脚本用于从剪贴板批量导入文本到字幕行。脚本需放置在 Aegisub 的 <code>automation/autoload/</code> 目录下。</p><p>脚本的 GitHub 源文件链接格式为 <code>https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/&lt;脚本名&gt;.lua</code>。</p><h3 id="replace-rows-—-替换行内容" tabindex="-1">replace-rows — 替换行内容 <a class="header-anchor" href="#replace-rows-—-替换行内容" aria-label="Permalink to &quot;replace-rows — 替换行内容&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/replace-rows.lua" target="_blank" rel="noreferrer">replace-rows.lua</a></p><p>将剪贴板中的文本按行替换到选中的对话行。剪贴板行数必须与选中行数一致，否则会取消操作并输出每行内容供核对。</p><p><strong>使用方法：</strong></p><ol><li>复制目标文本到剪贴板（每行对应一个待替换行）</li><li>在 Aegisub 中选中需要替换的行</li><li>运行「replace rows - 替换行内容」宏</li></ol><h3 id="replace-orig-—-替换原文行" tabindex="-1">replace-orig — 替换原文行 <a class="header-anchor" href="#replace-orig-—-替换原文行" aria-label="Permalink to &quot;replace-orig — 替换原文行&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/replace-orig.lua" target="_blank" rel="noreferrer">replace-orig.lua</a></p><p>与 <code>replace-rows</code> 类似，但仅替换样式为 <code>orig</code> 且效果为空或 <code>karaoke</code> 的行。剪贴板行数只需与符合条件的 <code>orig</code> 行数匹配。</p><p><strong>使用方法：</strong></p><ol><li>复制目标原文到剪贴板</li><li>选中包含 <code>orig</code> 行的区域</li><li>运行「replace orig - 替换原文行」宏</li></ol><h3 id="add-translation-—-添加翻译" tabindex="-1">add-translation — 添加翻译 <a class="header-anchor" href="#add-translation-—-添加翻译" aria-label="Permalink to &quot;add-translation — 添加翻译&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/add-translation.lua" target="_blank" rel="noreferrer">add-translation.lua</a></p><p>从剪贴板读取翻译文本，为每个 <code>orig</code> 行在其下方插入一条样式为 <code>ts</code> 的翻译行。翻译文本行数必须与有效 <code>orig</code> 行数一致。</p><p><strong>使用方法：</strong></p><ol><li>复制翻译文本到剪贴板（每行对应一句原文的翻译）</li><li>选中对应的 <code>orig</code> 行</li><li>运行「Add Translation - 添加翻译」宏</li><li>在弹出的对话框中： <ul><li><strong>语言</strong>：指定语言代码，如 <code>zh-CN</code>（会写入 <code>x-lang</code> 标记）</li><li><strong>保留相同部分</strong>：勾选后即使原文与翻译相同也会插入翻译行</li><li>可直接在文本框粘贴翻译内容替代剪贴板</li></ul></li></ol><h3 id="add-transliteration-—-添加音译" tabindex="-1">add-transliteration — 添加音译 <a class="header-anchor" href="#add-transliteration-—-添加音译" aria-label="Permalink to &quot;add-transliteration — 添加音译&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/aegisub/add-transliteration.lua" target="_blank" rel="noreferrer">add-transliteration.lua</a></p><p>与 <code>add-translation</code> 功能类似，但从剪贴板读取音译（罗马字）文本，为每个 <code>orig</code> 行在其下方插入一条样式为 <code>roma</code> 的音译行。</p><p><strong>使用方法：</strong></p><ol><li>复制音译文本到剪贴板</li><li>选中对应的 <code>orig</code> 行</li><li>运行「Add Transliteration - 添加音译」宏</li><li>在弹出的对话框中指定语言代码</li></ol><h2 id="字幕模板文件" tabindex="-1">字幕模板文件 <a class="header-anchor" href="#字幕模板文件" aria-label="Permalink to &quot;字幕模板文件&quot;">​</a></h2><p>以下 <code>.ass</code> 文件是 Aegisub 字幕模板（Automation Template），用于歌词的自动化渲染。文件需放置在对应的字幕项目中使用。</p><p>模板文件的 GitHub 源文件链接格式为 <code>https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/subtitles/&lt;文件名&gt;</code>。</p><h3 id="check-ass-—-基础检查模板" tabindex="-1">check.ass — 基础检查模板 <a class="header-anchor" href="#check-ass-—-基础检查模板" aria-label="Permalink to &quot;check.ass — 基础检查模板&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/subtitles/check.ass" target="_blank" rel="noreferrer">check.ass</a></p><p>一个轻量级的 Aegisub 字幕模板，用于快速检查和验证逐字歌词效果。</p><p><strong>模板结构：</strong></p><ul><li><strong>code once</strong>：初始化 <code>pre_end_time</code> 和 <code>pre_pos</code> 变量，用于追踪行间的时间位置</li><li><strong>code line</strong>：自动处理行间叠加——当两行的间隔不足 1000ms 时，后一行会自动升高以错位显示</li><li><strong>template furi</strong>：渲染假名/注音行，位于原文上方</li><li><strong>template syl</strong>：渲染逐字歌词行，位于原文下方，使用 <code>\\k</code> 标签控制逐字高亮</li><li><strong>template line</strong>（roma / ts）：渲染完整的罗马音行和翻译行</li></ul><p><strong>适用场景：</strong> 适用于制作过程中的快速预览，样式简洁，不包含复杂的标记处理逻辑。</p><h3 id="preview-ass-—-完整预览模板" tabindex="-1">preview.ass — 完整预览模板 <a class="header-anchor" href="#preview-ass-—-完整预览模板" aria-label="Permalink to &quot;preview.ass — 完整预览模板&quot;">​</a></h3><p><strong>源码：</strong> <a href="https://github.com/ranhengzhang/amll-ttml-db-raw-data/raw/refs/heads/main/subtitles/preview.ass" target="_blank" rel="noreferrer">preview.ass</a></p><p>一个功能完整的 Aegisub 字幕模板，支持多种歌词样式的同时渲染和更多视觉细节。</p><p><strong>样式定义：</strong></p><table tabindex="0"><thead><tr><th>样式名</th><th>用途</th></tr></thead><tbody><tr><td><code>orig</code></td><td>原文主歌词（128px，粗体）</td></tr><tr><td><code>orig-furigana</code></td><td>原文的假名注音</td></tr><tr><td><code>ts</code></td><td>翻译歌词（94px，斜体）</td></tr><tr><td><code>ts-furigana</code></td><td>翻译的假名注音</td></tr><tr><td><code>roma</code></td><td>罗马音/拼音（52px）</td></tr><tr><td><code>roma-furigana</code></td><td>罗马音的假名注音</td></tr></tbody></table><p><strong>模板功能：</strong></p><ul><li><strong>code once</strong>：定义辅助函数 <ul><li><code>mask_style()</code>：根据音节是否为 <code>\\k-Z</code>（零宽度）或 <code>\\k-zero</code> 生成不同的裁剪遮罩</li><li><code>pos_index()</code>：计算当前行在屏幕上的垂直位置，使连续行依次排列</li><li><code>ts_index()</code>：单独追踪翻译行位置，使翻译行紧贴原文下方</li></ul></li><li><strong>code line</strong>：每行开始时计算位置，处理 <code>x-bg</code> 背景行的特殊逻辑</li><li><strong>template syl</strong>（Layer 1）：渲染主歌词的逐字效果，支持 <code>\\k-Z</code> 零宽字符的隐藏</li><li><strong>template syl</strong>（Layer 2）：渲染带裁剪遮罩的歌词底层，用于实现渐进式高亮</li><li><strong>template pre-line mark</strong>：渲染行号标记（背景行加括号显示）</li><li><strong>template furi</strong>：渲染假名注音，位于原文上方</li><li><strong>template syl</strong>（roma）：逐字渲染罗马音行</li><li><strong>template syl</strong>（ts）：逐字渲染翻译行，水平位置与原文对齐</li></ul><p><strong>适用场景：</strong> 适用于正式制作流程，支持多语言歌词的完整预览，包含行号、背景行、假名注音等完整功能。</p>',42)])])}const u=e(l,[["render",i]]);export{h as __pageData,u as default};
